import {Config, Field} from 'alinea'

export const PostPage = Config.document('Post page', {
  fields: {
    title: Field.text('Title', {required: true}),
    path: Field.path('Path', {required: true}),
    excerpt: Field.text('Excerpt', {multiline: true}),
    body: Field.text('Body', {multiline: true})
  }
})

// entries/blog/BlogPage.tsx
import {Infer} from 'alinea'
import {BlogPage} from './BlogPage.schema'

type BlogData = Infer<typeof BlogPage>

export function BlogPageView({page, posts}: {page: BlogData; posts: Array<{id: string; title: string; url: string}>}) {
  return (
    <main>
      <h1>{page.title}</h1>
      {page.intro && <p>{page.intro}</p>}
      <ul>
        {posts.map(post => (
          <li key={post.id}>
            <a href={post.url}>{post.title}</a>
          </li>
        ))}
      </ul>
    </main>
  )
}

// entries/blog/BlogPostPage.tsx
import {Entry} from 'alinea/core/Entry'
import {notFound} from 'next/navigation'
import {cms} from '../../cms'
import {PostPage} from './PostPage.schema'

type PostLink = {id: string; title: string; url: string; path: string}

export async function BlogPostPageView({slug}: {slug: string}) {
  const post = await cms.get({url: `/blog/${slug}`, type: PostPage})
  if (!post) notFound()
  const blogPage = (await cms.get({url: '/blog'}))!

  const siblings = await cms.find({
    parentId: blogPage._id,
    select: {
      id: Entry.id,
      title: Entry.title,
      url: Entry.url,
      path: Entry.path
    }
  })

  const index = siblings.findIndex(candidate => candidate.path === slug)
  const previousPost: PostLink | null = index > 0 ? siblings[index - 1] : null
  const nextPost: PostLink | null = index >= 0 && index < siblings.length - 1 ? siblings[index + 1] : null

  return (
    <article>
      <h1>{post.title}</h1>
      <p>{post.body}</p>
      {(previousPost || nextPost) && (
        <nav aria-label="Post navigation">
          <h2>Next/Previous blogpost</h2>
          <ul>
            {previousPost && (
              <li>
                <a href={previousPost.url}>Previous: {previousPost.title}</a>
              </li>
            )}
            {nextPost && (
              <li>
                <a href={nextPost.url}>Next: {nextPost.title}</a>
              </li>
            )}
          </ul>
        </nav>
      )}
    </article>
  )
}

