// app/blog/page.tsx
import {Entry} from 'alinea/core/Entry'
import {cms} from '@/cms'
import {BlogPageView} from '@/entries/blog/BlogPage'

export default async function BlogRoute() {
  const page = await cms.get({url: '/blog'})
  const posts = await cms.find({
    parentId: page._id,
    select: {
      id: Entry.id,
      title: Entry.title,
      url: Entry.url
    }
  })

  return <BlogPageView page={page} posts={posts} />
}

// app/blog/[slug]/page.tsx
import {Entry} from 'alinea/core/Entry'
import {cms} from '@/cms'
import {BlogPostPageView} from '@/entries/blog/BlogPostPage'
import {PostPage} from '@/entries/blog/PostPage.schema'

export async function generateStaticParams() {
  const paths = await cms.find({
    type: PostPage,
    select: Entry.path
  })
  return paths.map(slug => ({slug}))
}

export default async function BlogPostRoute({params}: {params: {slug: string}}) {
  return <BlogPostPageView slug={params.slug} />
}
